		out.Disposition = ConflictRecoveryMerged
		return out
	}

	if in.ConflictResolver != nil {
		resolvedTip, isBlocking, resolveErr := in.ConflictResolver(ctx, in.Bead.ID, report.PreserveRef, in.ProjectRoot)
		if resolveErr == nil && resolvedTip != "" {
			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
				Kind:      "land-conflict-auto-recovered",
				Summary:   "preserved iteration resolved by focused conflict-resolve agent",
				Body:      fmt.Sprintf("preserve_ref=%s\nnew_tip=%s", report.PreserveRef, resolvedTip),
				Actor:     in.Assignee,
				Source:    "ddx work",
				CreatedAt: now().UTC(),
			})
			report.Status = ExecuteBeadStatusSuccess
			report.ResultRev = resolvedTip
			report.Detail = "auto-recovered: focused conflict-resolve agent landed preserved iteration"
			if err := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); err != nil {
				out.StoreErrOp = "CloseWithEvidence"
				out.StoreErr = err
				out.Report = report
				return out
			}
			out.Report = report
			out.Disposition = ConflictRecoveryMerged
			return out
		}
		if isBlocking {
			report.Status = ExecuteBeadStatusLandConflictOperatorRequired
		} else {
			report.Status = ExecuteBeadStatusLandConflictUnresolvable
		}
	} else {
		report.Status = ExecuteBeadStatusLandConflictUnresolvable
	}

	autoErrMsg := ""
	if autoErr != nil {
		autoErrMsg = autoErr.Error()
	}
	body, mErr := json.Marshal(map[string]any{
		"preserve_ref":     report.PreserveRef,
		"base_rev":         report.BaseRev,
		"result_rev":       report.ResultRev,
		"session_id":       report.SessionID,
		"auto_merge_error": autoErrMsg,
		"rescue_command":   landConflictRescueCommand(report.PreserveRef),
	})
	bodyStr := fmt.Sprintf("preserve_ref=%s\nrescue_command=%s", report.PreserveRef, landConflictRescueCommand(report.PreserveRef))
	if mErr == nil {
		bodyStr = string(body)
	}
	eventKind := "land-conflict-unresolvable"
	if report.Status == ExecuteBeadStatusLandConflictOperatorRequired {
		eventKind = "land-conflict-operator-required"
	}
	_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
		Kind:      eventKind,
		Summary:   "preserved iteration could not be auto-recovered; parked for operator",
		Body:      bodyStr,
		Actor:     in.Assignee,
		Source:    "ddx work",
		CreatedAt: now().UTC(),
	})
	report.Detail = landConflictRescueDetail(report.Status, report.PreserveRef)

	if report.Status == ExecuteBeadStatusLandConflictOperatorRequired {
		if err := in.Store.Unclaim(in.Bead.ID); err != nil {
			out.StoreErrOp = "Unclaim"
			out.StoreErr = err
			out.Report = report
			return out
		}
		if err := in.Store.ParkToProposed(in.Bead.ID, bead.ParkConflictRecovery, func(b *bead.Bead) {
			// Migration-only cleanup: defensive removal for legacy rows that escaped
			// the lifecycle migration or arrived via external import.
			b.Labels = removeBeadLabels(b.Labels, TriageNeedsHumanLabel, bead.LabelNeedsHuman, bead.LabelNeedsInvestigation)
			bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{
				Reason:          "land conflict requires operator judgment",
				Since:           now().UTC().Format(time.RFC3339),
				Source:          "ddx work",
				SuggestedAction: "resolve the preserved land conflict manually or split the bead",
				Summary:         "land conflict requires operator decision",
			})
		}); err != nil {
			out.StoreErrOp = "ParkToProposed"
			out.StoreErr = err
			out.Report = report
			return out
		}
		out.Report = report
		out.Disposition = ConflictRecoveryOperatorRequired
		return out
	}

	if err := in.Store.Unclaim(in.Bead.ID); err != nil {
		out.StoreErrOp = "Unclaim"
		out.StoreErr = err
		out.Report = report
		return out
	}
	parkUntil := now().UTC().Add(in.Cooldown)
	if err := in.Store.SetExecutionCooldown(in.Bead.ID, parkUntil, report.Status, report.Detail, in.Report.BaseRev); err != nil {
		out.StoreErrOp = "SetExecutionCooldown"
		out.StoreErr = err
		out.Report = report
		return out
	}
	report.RetryAfter = parkUntil.Format(time.RFC3339)

	out.Report = report
	out.Disposition = ConflictRecoveryPark
	return out
}

func landConflictRescueCommand(preserveRef string) string {
	if preserveRef == "" {
		return ""
	}
	return "git merge --no-ff " + preserveRef
}

func landConflictRescueDetail(status, preserveRef string) string {
	if preserveRef == "" {
		return status
	}
	return fmt.Sprintf("%s: preserve_ref=%s rescue_command=%s", status, preserveRef, landConflictRescueCommand(preserveRef))
}

