	if err := in.Store.SetExecutionCooldown(in.Bead.ID, parkUntil, report.Status, report.Detail, in.Report.BaseRev); err != nil {
		out.StoreErrOp = "SetExecutionCooldown"
		out.StoreErr = err
		out.Report = report
		return out
	}
